type SkillFile struct {
	Path    string
	Content string
}

// SkillLocation controls where a skill is written on disk.
type SkillLocation string

const (
	SkillLocationGlobal  SkillLocation = "global"
	SkillLocationProject SkillLocation = "project"
)

