49	// Init installs hooks into the user's home directory for all selected targets,
50	// registers the current working directory as a project dir for project-scoped
51	// skills, and persists the configuration.
52	func (m *Module) Init(ctx context.Context, opts InitOptions) (*InitResult, error) {
53		home, err := os.UserHomeDir()
54		if err != nil {
55			return nil, fmt.Errorf("failed to get home directory: %w", err)
56		}
57	
58		cwd, err := os.Getwd()
59		if err != nil {
60			return nil, fmt.Errorf("failed to get working directory: %w", err)
61		}
62	
63		if err := InstallHooks(opts.Targets, home, cwd); err != nil {
64			return nil, fmt.Errorf("failed to install hooks: %w", err)
65		}
66	
67		targetPaths := TargetPaths(opts.Targets, home, cwd)
68	
69		skillsCfg, err := m.configManager.LoadSkillsConfig()
70		if err != nil {
71			skillsCfg = &config.SkillsConfig{}
72		}
73	
74		skillsCfg.Targets = mergeUnique(skillsCfg.Targets, targetPaths)
75		skillsCfg.ProjectDirs = appendUnique(skillsCfg.ProjectDirs, cwd)
76	
77		if err := m.configManager.SaveSkillsConfig(skillsCfg); err != nil {
78			return nil, fmt.Errorf("failed to save skills config: %w", err)
79		}
80	
81		return &InitResult{InstalledTargets: targetPaths}, nil
82	}
