84	func appendUnique(slice []string, s string) []string {
85		for _, v := range slice {
86			if v == s {
87				return slice
88			}
89		}
90		return append(slice, s)
91	}
92	
93	func mergeUnique(existing, additions []string) []string {
94		seen := make(map[string]bool, len(existing))
95		for _, v := range existing {
96			seen[v] = true
97		}
98		result := make([]string, len(existing))
99		copy(result, existing)
100		for _, v := range additions {
101			if !seen[v] {
102				result = append(result, v)
103				seen[v] = true
104			}
105		}
106		return result
107	}
