137	// LoadSkills fetches skills from Port and writes them to the appropriate targets.
138	// Skills with location="project" are written to the current working directory;
139	// all other skills are written to the configured global AI tool directories.
140	func (m *Module) LoadSkills(ctx context.Context, opts LoadSkillsOptions) (*LoadSkillsResult, error) {
141		skillsCfg, err := m.configManager.LoadSkillsConfig()
142		if err != nil {
143			skillsCfg = &config.SkillsConfig{}
144		}
145	
146		if len(skillsCfg.Targets) == 0 {
147			home, _ := os.UserHomeDir()
148			cwd, _ := os.Getwd()
149			skillsCfg.Targets = TargetPaths(DefaultHookTargets(), home, cwd)
150		}
151	
152		fetched, err := FetchSkills(ctx, m.client)
153		if err != nil {
154			return nil, err
155		}
156	
157		if opts.SelectAll || opts.SelectAllGroups || opts.SelectAllUngrouped ||
158			len(opts.SelectedGroups) > 0 || len(opts.SelectedSkills) > 0 {
159			skillsCfg.SelectAll = opts.SelectAll
160			skillsCfg.SelectAllGroups = opts.SelectAllGroups
161			skillsCfg.SelectAllUngrouped = opts.SelectAllUngrouped
162			skillsCfg.SelectedGroups = opts.SelectedGroups
163			skillsCfg.SelectedSkills = opts.SelectedSkills
164		}
165	
166		skills := FilterSkills(fetched, skillsCfg.SelectAll, skillsCfg.SelectAllGroups, skillsCfg.SelectAllUngrouped, skillsCfg.SelectedGroups, skillsCfg.SelectedSkills)
167	
168		if err := WriteSkills(skills, fetched.Groups, skillsCfg.Targets, skillsCfg.ProjectDirs); err != nil {
169			return nil, fmt.Errorf("failed to write skills: %w", err)
170		}
171	
172		skillsCfg.LastSyncedAt = time.Now().UTC().Format(time.RFC3339)
173		if err := m.configManager.SaveSkillsConfig(skillsCfg); err != nil {
174			return nil, fmt.Errorf("failed to save skills config: %w", err)
175		}
176	
177		requiredCount := 0
178		globalSkillCount := 0
179		projectSkillCount := 0
180		for _, s := range skills {
181			if s.Required {
182				requiredCount++
183			}
184			if s.Location == SkillLocationProject {
185				projectSkillCount++
186			} else {
187				globalSkillCount++
188			}
189		}
190	
191		projectTargets := buildProjectTargets(skillsCfg.Targets, skillsCfg.ProjectDirs)
192	
193		targetResults := make([]TargetResult, 0, len(skillsCfg.Targets)+len(projectTargets))
194		for _, t := range skillsCfg.Targets {
195			if isGitHubCopilotSkillRoot(t) {
196				continue
197			}
198			targetResults = append(targetResults, TargetResult{
199				Path:       t,
200				SkillCount: globalSkillCount,
201				IsProject:  false,
202			})
203		}
204		for _, t := range projectTargets {
205			if isGitHubCopilotSkillRoot(t) {
206				continue
207			}
208			targetResults = append(targetResults, TargetResult{
209				Path:       t,
210				SkillCount: projectSkillCount,
211				IsProject:  true,
212			})
213		}
214		copilotRoots := uniqCopilotSkillRoots(append(append([]string{}, skillsCfg.Targets...), projectTargets...))
215		for _, root := range copilotRoots {
216			targetResults = append(targetResults, TargetResult{
217				Path:              root,
218				SkillCount:        globalSkillCount + projectSkillCount,
219				IsProject:         false,
220				GitHubCopilotRepo: true,
221			})
222		}
223	
224		return &LoadSkillsResult{
225			RequiredCount: requiredCount,
226			SelectedCount: len(skills) - requiredCount,
227			TargetCount:   len(skillsCfg.Targets),
228			TargetResults: targetResults,
229		}, nil
230	}
